import json
import psycopg2
import boto3

def lambda_handler(event, context):
    client = boto3.client('secretsmanager')
    response = client.get_secret_value(SecretId='db-credentials')

    db_credentials = json.loads(response['SecretString'])
    connection_string = db_credentials['connection_string']
    username, password, hostname, database = map(lambda x: x['value'], response['Parameters'])

    try:
        conn = psycopg2.connect(database=database, user=username, password=password, host=hostname)
        cur = conn.cursor()
        cur.execute("SELECT * FROM your_table")
        rows = cur.fetchall()
        result = [dict(zip([column[0] for column in cur.description], row)) for row in rows]

        response = {
            'statusCode': 200,
            'body': json.dumps(result)
        }
    except Exception as e:
        response = {
            'statusCode': 500,
            'body': str(e)
        }

    finally:
        conn.close()
    return response